function Nav({active,onNav}){
  const[menuOpen,setMenuOpen]=useState(false);
  const items=[{id:"home",l:"Home"},{id:"education",l:"Education"},{id:"business",l:"Business"},{id:"horizon",l:"Horizon Map"},{id:"insight",l:"Insight"},{id:"about",l:"About"},{id:"contact",l:"Contact"}];
  return(<><nav className="main-nav" style={{height:120,borderBottom:`1px solid ${C.w05}`,position:"sticky",top:0,zIndex:100,background:"rgba(11,25,44,0.94)",backdropFilter:"blur(20px)",WebkitBackdropFilter:"blur(20px)"}}><div className="responsive-container" style={{height:"100%",display:"flex",justifyContent:"space-between",alignItems:"center"}}><div onClick={()=>onNav("home")} style={{display:"flex",alignItems:"center",cursor:"pointer"}}><img src={LOGO_SRC} alt="PROVIO" style={{height:100,width:"auto",display:"block",objectFit:"contain"}}/></div><div className="nav-desktop">{items.map(i=>(<button key={i.id} onClick={()=>onNav(i.id)} style={{padding:"6px 16px",borderRadius:4,fontSize:13,fontWeight:active===i.id?600:400,cursor:"pointer",fontFamily:"Open Sans",transition:"color .18s",background:"transparent",border:"none",color:active===i.id?C.w:C.w4,borderBottom:active===i.id?"2px solid "+C.teal:"2px solid transparent",position:"relative",top:1}}>{i.l}</button>))}</div><button className="nav-mobile-btn" onClick={()=>setMenuOpen(true)} aria-label="Open menu"><svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><line x1="3" y1="6" x2="21" y2="6"/><line x1="3" y1="12" x2="21" y2="12"/><line x1="3" y1="18" x2="21" y2="18"/></svg></button></div></nav>{menuOpen&&<div className="mobile-menu"><button className="mobile-menu-close" onClick={()=>setMenuOpen(false)} aria-label="Close menu">✕</button>{items.map(i=>(<button key={i.id} onClick={()=>{onNav(i.id);setMenuOpen(false)}} style={{color:active===i.id?C.teal:undefined}}>{i.l}</button>))}</div>}</>);
}
function Footer({onNav}){return(<footer style={{borderTop:`1px solid ${C.w05}`,padding:"48px 0",background:C.navy}}><div className="responsive-container footer-inner"><div style={{cursor:"pointer"}} onClick={()=>onNav("home")}><img src={LOGO_SRC} alt="PROVIO" style={{height:70,width:"auto",display:"block",objectFit:"contain"}}/></div><div style={{display:"flex",gap:28,alignItems:"center",flexWrap:"wrap",justifyContent:"center"}}>{[{id:"education",l:"Education"},{id:"business",l:"Business"},{id:"horizon",l:"Horizon Map"},{id:"insight",l:"Insight"},{id:"about",l:"About"},{id:"contact",l:"Contact"}].map(i=>(<button key={i.id} onClick={()=>onNav(i.id)} style={{background:"none",border:"none",color:C.w4,fontSize:12,cursor:"pointer",fontFamily:"Open Sans",transition:"color .18s"}} onMouseOver={e=>e.currentTarget.style.color=C.w6} onMouseOut={e=>e.currentTarget.style.color=C.w4}>{i.l}</button>))}</div><div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:6,marginTop:8}}><a href="mailto:jon.swaby@uk.mcd.com" style={{fontSize:11,color:C.teal,textDecoration:"none"}}>jon.swaby@uk.mcd.com</a><span style={{fontSize:10,color:C.slate}}>Community Interest Company</span><span style={{fontSize:10,color:C.slate}}>© 2026 Provio</span></div></div></footer>);}
function SL({text,color=C.teal}){return(<div style={{display:"flex",alignItems:"center",gap:8,marginBottom:14}}><div style={{width:24,height:1,background:color}}/><span style={{fontSize:10,fontWeight:600,letterSpacing:"0.25em",color,textTransform:"uppercase"}}>{text}</span></div>);}
function Btn({children,onClick,primary,style:s}){return(<button onClick={onClick} style={{padding:"13px 28px",borderRadius:10,fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:"Montserrat",transition:"all .2s",background:primary?C.teal:"transparent",color:primary?C.navy:C.w6,border:primary?"none":`1px solid ${C.w1}`,boxShadow:primary?`0 0 30px ${C.teal}20`:"none",...s}} onMouseOver={e=>primary&&(e.target.style.transform="translateY(-2px)")} onMouseOut={e=>primary&&(e.target.style.transform="translateY(0)")}>{children}</button>);}

// Survey question renderer
function SurveyQ({q,qi,response,onAnswer,accent=C.teal,hasScore=true}){
  return(<div style={{marginBottom:24,paddingBottom:24,borderBottom:`1px solid ${C.w03}`}}><p style={{fontSize:13,color:C.w8,lineHeight:1.5,marginBottom:12}}><span style={{color:accent,fontWeight:600,marginRight:6}}>{qi+1}.</span>{q.text}</p><div style={{display:"flex",flexDirection:"column",gap:5}}>{q.options.map((opt,oi)=>{const label=hasScore?opt.label:opt;const val=hasScore?opt.score:oi;const sel=response===val;return(<button key={oi} onClick={()=>onAnswer(val)} style={{padding:"11px 14px",borderRadius:8,textAlign:"left",cursor:"pointer",fontSize:12,lineHeight:1.4,transition:"all .2s",fontFamily:"Open Sans",background:sel?`${accent}10`:C.w03,border:`1px solid ${sel?accent+"40":C.w05}`,color:sel?accent:C.w6,transform:sel?"translateX(3px)":"translateX(0)"}}><span style={{display:"inline-flex",width:18,height:18,borderRadius:"50%",alignItems:"center",justifyContent:"center",marginRight:8,fontSize:9,fontWeight:600,background:sel?accent:C.w05,color:sel?C.navy:C.w4}}>{String.fromCharCode(97+oi)}</span>{label}</button>);})}</div></div>);
}

