            <div><label style={{fontSize:10,color:C.w4,display:"block",marginBottom:3}}>Email</label><input value={contactForm.email} onChange={e=>setContactForm(p=>({...p,email:e.target.value}))} placeholder="your@email.com" style={{width:"100%",padding:"10px 12px",background:C.w05,border:`1px solid ${C.w1}`,borderRadius:7,color:C.w,fontSize:12,outline:"none",fontFamily:"Open Sans"}}/></div>
